const entrada = $('Normalizar Entrada').first().json;
const results = $input.all().map((item) => item.json).filter((hit) => hit?.country);
const ufEstados = {
  ac: 'acre', al: 'alagoas', am: 'amazonas', ap: 'amapa', ba: 'bahia',
  ce: 'ceara', df: 'distrito federal', es: 'espirito santo', go: 'goias',
  ma: 'maranhao', mg: 'minas gerais', ms: 'mato grosso do sul', mt: 'mato grosso',
  pa: 'para', pb: 'paraiba', pe: 'pernambuco', pi: 'piaui', pr: 'parana',
  rj: 'rio de janeiro', rn: 'rio grande do norte', ro: 'rondonia', rr: 'roraima',
  rs: 'rio grande do sul', sc: 'santa catarina', se: 'sergipe', sp: 'sao paulo', to: 'tocantins',
};
const norm = (s) => (s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
const cidadeBusca = norm(entrada.cidade);
const estadoEsperado = ufEstados[entrada.uf];
const nomeCombina = (hit) => {
  const candidatos = [hit.name, hit.local_names?.pt].filter(Boolean).map(norm);
  return candidatos.some((n) => n === cidadeBusca || n.startsWith(cidadeBusca + ' '));
};
const hit = estadoEsperado && cidadeBusca
  ? results.find((h) => h.country === 'BR' && norm(h.state) === estadoEsperado && nomeCombina(h))
  : null;

return [{
  json: {
    localValid: Boolean(hit),
    lat: hit?.lat ?? 0,
    lon: hit?.lon ?? 0,
    cidadeNome: hit?.local_names?.pt || hit?.name || entrada.cidade,
    chatId: entrada.chatId,
  },
}];

